use std::io::Read;

fn main() {
    let mut input = String::new();
    std::io::stdin().read_to_string(&mut input).expect("Err: read line failed");
    let vec = input.lines().map(|line| {
        line.trim().split_whitespace().map(|word| {
            word.parse::<i32>().expect("Err: parse to i32 failed")
        }).collect::<Vec<i32>>()
    }).collect::<Vec<Vec<i32>>>();

    for number in &vec[1] {
        for digit in &vec[2] {
            if digit == number {
                print!("{} ", &digit);
            }
        }
    }

    println!("");
}
